import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ChevronLeft, ChevronRight, User, Trash2, X, Save, FileText, Hash, CreditCard } from 'lucide-react';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  const [filtroData, setFiltroData] = useState({
    mes: new Date().getMonth(),
    ano: new Date().getFullYear()
  });

  const mesesNominais = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
  ];

  useEffect(() => {
    fetchDespesas();
  }, [filtroData]);

  async function fetchDespesas() {
    const { data, error } = await supabase.from('compras').select('*').order('data_compra', { ascending: false });
    if (!error && data) {
      const projetadas = [];
      data.forEach(item => {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const dataCompra = new Date(item.data_compra);
          // Ajuste para evitar problemas de fuso horário na projeção de meses
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({
              ...item,
              parcelaAtual: i + 1,
              valorParcela: parseFloat(item.valor_total) / numParcelas
            });
          }
        }
      });
      setDespesas(projetadas);
    }
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    const { error } = await supabase
      .from('compras')
      .update({
        descricao: itemParaEditar.descricao,
        loja: itemParaEditar.loja,
        responsavel: itemParaEditar.responsavel,
        valor_total: parseFloat(itemParaEditar.valor_total),
        pedido: itemParaEditar.pedido,
        nota_fiscal: itemParaEditar.nota_fiscal,
        cartao: itemParaEditar.cartao // Incluído na atualização
      })
      .eq('id', itemParaEditar.id);

    if (error) alert("Erro ao atualizar: " + error.message);
    else {
      setItemParaEditar(null);
      fetchDespesas();
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Deseja excluir esta despesa permanentemente?")) {
      const { error } = await supabase.from('compras').delete().eq('id', id);
      if (!error) {
        setItemParaEditar(null);
        fetchDespesas();
      }
    }
  };

  const mudarMes = (direcao) => {
    let novoMes = filtroData.mes + direcao;
    let novoAno = filtroData.ano;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    else if (novoMes > 11) { novoMes = 0; novoAno++; }
    setFiltroData({ mes: novoMes, ano: novoAno });
  };

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h2>Extrato de Gastos</h2>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', background: 'white', padding: '10px 20px', borderRadius: '12px', boxShadow: 'var(--shadow)' }}>
          <button onClick={() => mudarMes(-1)} style={navBtnStyle}><ChevronLeft /></button>
          <div style={{ textAlign: 'center', minWidth: '120px' }}>
            <strong style={{ display: 'block' }}>{mesesNominais[filtroData.mes]}</strong>
            <small style={{ color: 'var(--text-muted)' }}>{filtroData.ano}</small>
          </div>
          <button onClick={() => mudarMes(1)} style={navBtnStyle}><ChevronRight /></button>
        </div>
      </div>

      <div className="card" style={{ padding: '0', overflowX: 'auto' }}>
        <table style={{ minWidth: '1000px' }}> {/* Aumentado min-width para acomodar novas colunas */}
          <thead>
            <tr>
              <th>Data</th>
              <th>Responsável</th>
              <th>Descrição</th>
              <th>Loja</th>
              <th>N° Pedido</th>
              <th>Nota Fiscal</th>
              <th>Cartão</th>
              <th>Parcela</th>
              <th style={{ textAlign: 'right' }}>Valor Parcela</th>
            </tr>
          </thead>
          <tbody>
            {despesas.length === 0 ? (
              <tr><td colSpan="9" style={{ textAlign: 'center', padding: '60px', color: 'var(--text-muted)' }}>Nenhum lançamento para este mês.</td></tr>
            ) : (
              despesas.map((item, idx) => (
                <tr key={`${item.id}-${idx}`} className="clickable-row" onClick={() => setItemParaEditar(item)}>
                  <td>{new Date(item.data_compra).toLocaleDateString('pt-BR', {day:'2-digit', month:'2-digit'})}</td>
                  <td style={{ fontWeight: '600', color: 'var(--primary)' }}>{item.responsavel || '-'}</td>
                  <td style={{ fontWeight: '500' }}>{item.descricao}</td>
                  <td>{item.loja || '-'}</td>
                  <td style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>{item.pedido || '-'}</td>
                  <td style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>{item.nota_fiscal || '-'}</td>
                  <td>
                    {item.cartao ? (
                      <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.85rem' }}>
                        <CreditCard size={14} opacity={0.6} /> {item.cartao}
                      </div>
                    ) : '-'}
                  </td>
                  <td>
                    <span style={{ background: item.parcelado ? 'var(--primary-light)' : '#f0fdf4', color: item.parcelado ? 'var(--primary)' : '#16a34a', padding: '4px 8px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 'bold' }}>
                      {item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}
                    </span>
                  </td>
                  <td style={{ fontWeight: '700', textAlign: 'right' }}>
                    R$ {item.valorParcela.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
      
      <div style={{ marginTop: '20px', textAlign: 'right' }}>
        <p style={{ color: 'var(--text-muted)', marginBottom: '5px' }}>Total do Mês:</p>
        <h2 style={{ color: 'var(--primary)' }}>
          R$ {despesas.reduce((acc, curr) => acc + curr.valorParcela, 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
        </h2>
      </div>

      {itemParaEditar && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
              <h3 style={{ margin: 0 }}>Editar Lançamento</h3>
              <button onClick={() => setItemParaEditar(null)} style={{ border: 'none', background: 'none', cursor: 'pointer' }}><X /></button>
            </div>
            <form onSubmit={handleUpdate} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <input className="form-control" value={itemParaEditar.responsavel} onChange={e => setItemParaEditar({...itemParaEditar, responsavel: e.target.value})} placeholder="Responsável" />
                <input className="form-control" value={itemParaEditar.cartao} onChange={e => setItemParaEditar({...itemParaEditar, cartao: e.target.value})} placeholder="Cartão" />
              </div>
              <input className="form-control" value={itemParaEditar.descricao} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} placeholder="Descrição" required />
              <input className="form-control" value={itemParaEditar.loja} onChange={e => setItemParaEditar({...itemParaEditar, loja: e.target.value})} placeholder="Loja" />
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <input className="form-control" value={itemParaEditar.pedido} onChange={e => setItemParaEditar({...itemParaEditar, pedido: e.target.value})} placeholder="Pedido" />
                <input className="form-control" value={itemParaEditar.nota_fiscal} onChange={e => setItemParaEditar({...itemParaEditar, nota_fiscal: e.target.value})} placeholder="NF" />
              </div>
              <label style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Valor Total da Compra (R$):</label>
              <input type="number" step="0.01" className="form-control" value={itemParaEditar.valor_total} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} required />
              
              <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
                <button type="submit" className="btn-primary" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                  <Save size={18} /> Salvar
                </button>
                <button type="button" onClick={() => handleDelete(itemParaEditar.id)} style={{ background: 'var(--danger)', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer' }}>
                  <Trash2 size={20} />
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const navBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', color: 'var(--primary)' };

export default Listagem;
